        "CHAR(1)", "CHAR(10)", "CHAR(50)", "CHAR(100)", "CHAR(255)"
    ));

    public SchemaManagerService(DataSource dataSource) {
        this.jdbcTemplate = new JdbcTemplate(dataSource);
    }

    /**
     * Adds a new column to the products table.
     *
     * @param columnName the name of the column to add
     * @param columnType the type of the column (e.g., "VARCHAR(255)")
     * @throws IllegalArgumentException if column name is invalid or column type is not supported
     * @throws RuntimeException if SQL execution fails
     */
    public void addProductColumn(String columnName, String columnType) {
        // Validate inputs
        if (columnName == null || columnName.trim().isEmpty()) {
            throw new IllegalArgumentException("Column name cannot be null or empty");
        }

        // Sanitize column name to prevent SQL injection
        if (!columnName.matches("^[a-zA-Z][a-zA-Z0-9_]*$")) {
            throw new IllegalArgumentException("Invalid column name format");
        }

        if (columnType == null || columnType.trim().isEmpty()) {
            throw new IllegalArgumentException("Column type cannot be null or empty");
        }

        // Normalize column type
        String normalizedColumnType = columnType.trim().toUpperCase();

        // Check if column type is allowed
        if (!VALID_COLUMN_TYPES.contains(normalizedColumnType)) {
            throw new IllegalArgumentException("Unsupported column type: " + columnType);
        }

        // Construct and execute ALTER TABLE statement
        String sql = "ALTER TABLE products ADD COLUMN " + columnName + " " + normalizedColumnType;

        try {
            jdbcTemplate.execute(sql);
        } catch (Exception e) {
            throw new RuntimeException("Failed to add column '" + columnName + "' of type '" + columnType + 
                                     "' to products table: " + e.getMessage(), e);
        }
    }
}
